CREATE INDEX IF NOT EXISTS idx_workshop_tasks_status ON workshop_tasks(status);
CREATE INDEX IF NOT EXISTS idx_workshop_tasks_created ON workshop_tasks(created_at DESC);

-- ============================================================
-- Auto-update updated_at on threads
-- ============================================================
CREATE OR REPLACE FUNCTION update_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS threads_updated_at ON threads;
CREATE TRIGGER threads_updated_at
  BEFORE UPDATE ON threads
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at();

-- ============================================================
-- Update thread.updated_at when a message is inserted
-- ============================================================
CREATE OR REPLACE FUNCTION touch_thread_on_message()
RETURNS TRIGGER AS $$
BEGIN
  UPDATE threads SET updated_at = NOW() WHERE id = NEW.thread_id;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS messages_touch_thread ON messages;
CREATE TRIGGER messages_touch_thread
  AFTER INSERT ON messages
  FOR EACH ROW
  EXECUTE FUNCTION touch_thread_on_message();

-- ============================================================
-- durable-chat.sql
-- ============================================================
-- Durable chat: runs are queued in the DB, executed by the chat-runner, and
-- streamed to the UI via Realtime — so a generation survives the UI connection
-- dropping (close the laptop, Spectre keeps going; reattach anywhere). Rerunnable.

-- Per-message generation status. Existing rows are complete -> 'done'.
-- New flow: assistant placeholder 'queued' -> 'running' -> 'done'|'error'|'cancelled'.
alter table messages add column if not exists status text not null default 'done';

-- Runner lease columns (mirrors the locked_at/locked_by pattern on scheduled_jobs).
-- The chat-runner sets both atomically with the queued->running claim, heartbeats
-- locked_at every 60 s during execution, and the boot orphan-recovery only reclaims
-- rows whose lease is null or older than STALE_MS (20 min default) — leaving live
-- in-flight runs on sibling/surviving runners untouched.
alter table messages add column if not exists locked_at timestamptz;
alter table messages add column if not exists locked_by text;

create index if not exists messages_status_idx
  on messages (status)
  where status in ('queued', 'running', 'cancelled');

-- Realtime so the UI viewer sees the assistant row fill in live and the runner
-- can pick up work. replica identity full -> UPDATE payloads include content.
alter table messages replica identity full;

do $$
begin
  if not exists (
    select 1 from pg_publication_tables
    where pubname = 'supabase_realtime' and tablename = 'messages'
  ) then
    alter publication supabase_realtime add table messages;
  end if;
end $$;

-- ============================================================
-- channels.sql
-- ============================================================
-- Messaging channels: inbound webhook -> durable Spectre turn -> outbound delivery.
-- A channel chat reuses ONE thread per (channel, sender) so context persists; the
-- thread carries metadata.channel = { type, chat_id } so the outbound worker knows
-- where to send the reply. Default-deny: only allowed senders are acted on.

create table if not exists channel_accounts (
  id uuid primary key default gen_random_uuid(),
  channel text not null,
  sender_id text not null,
  thread_id uuid references threads(id) on delete set null,
  allowed boolean not null default false,
  created_at timestamptz not null default now(),
  unique (channel, sender_id)
);

-- Outbound dedupe marker: an assistant reply on a channel-bound thread is sent
-- exactly once, then stamped delivered_at. Durable (survives worker restarts) —
-- the chat-runner's orphan recovery shows why in-process sent-sets are unsafe.
alter table messages add column if not exists delivered_at timestamptz;

-- The outbound worker scans for undelivered, finished assistant replies.
create index if not exists idx_messages_undelivered
  on messages (thread_id)
  where delivered_at is null and status = 'done' and role = 'assistant';

-- Service role full access; anon none (this is the inbound sender allowlist —
-- anon write access would let anyone allowlist themselves).
alter table channel_accounts enable row level security;

drop policy if exists "service role full access" on channel_accounts;
DROP POLICY IF EXISTS "service role full access" ON channel_accounts;
CREATE POLICY "service role full access" ON channel_accounts
  using (auth.role() = 'service_role')
  with check (auth.role() = 'service_role');

-- ============================================================
-- memory-embeddings.sql
-- ============================================================
-- Semantic memory: local-embedder vector search.
-- The default embedder is local Ollama nomic-embed-text (768-dim); the original
-- column was sized for OpenAI (1536). Resize + add a cosine-similarity RPC.
-- Safe to rerun. If you switch to OpenAI embeddings, change 768 -> 1536 here
-- and re-embed.

-- Also removes the old ivfflat index on installs that predate the exact-KNN
-- switch (see note below).
drop index if exists idx_memory_embedding;

-- Existing rows have no embedding yet, so dropping/re-adding is lossless.
alter table memory drop column if exists embedding;
alter table memory ADD COLUMN IF NOT EXISTS embedding vector(768);

-- NOTE: deliberately NO ivfflat/approximate index (same rule as
-- generated_media/pdf_chunks). ivfflat with a fixed `lists` count silently
-- returns 0 rows on small tables (a single-probe query lands in an empty
-- list), which killed recall on fresh installs. Memory stays small after the
-- nightly dedup/decay, so an exact KNN sort is sub-millisecond AND always
-- correct. If memory ever grows past ~100k rows, add an HNSW index (no
-- empty-probe hole) — not ivfflat.

-- Top-K cosine similarity over memories (optionally filtered by category).
create or replace function match_memory(
  query_embedding vector(768),
  match_count int default 8,
  filter_category text default null
)
returns table (
  id uuid,
  content text,
  category text,
  importance smallint,
  similarity float
)
language sql stable
as $$
  select m.id, m.content, m.category, m.importance,
         1 - (m.embedding <=> query_embedding) as similarity
  from memory m
  where m.embedding is not null
    and (filter_category is null or m.category = filter_category)
  order by m.embedding <=> query_embedding
  limit match_count;
$$;

-- ============================================================
-- messages-embeddings.sql
-- ============================================================
-- Cross-thread message recall: semantic search over raw chat messages so Spectre
-- can answer "what did we decide/discuss in that OTHER conversation last week".
--
-- Mirrors the memory-embeddings pattern exactly: a local-embedder vector(768)
-- column (Ollama nomic-embed-text) + a top-K cosine RPC. Messages are embedded
-- lazily in the background (the nightly dream backfill), NEVER on the chat write
-- path, so sends stay fast. Safe to rerun. If you switch to OpenAI embeddings,
-- change 768 -> 1536 here and re-embed.

alter table messages add column if not exists embedding vector(768);

-- NOTE: deliberately NO ivfflat/approximate index (same rule as
-- generated_media/pdf_chunks). ivfflat with a fixed `lists` count silently
-- returns 0 rows on small tables (a single-probe query lands in an empty
-- list), which killed cross-thread recall on fresh installs. match_messages
-- does an exact `order by embedding <=> query` instead — correct at every
-- size, fast at single-user scale. If messages grows past ~100k embedded
-- rows, add an HNSW index (no empty-probe hole) — not ivfflat. The drop also
-- migrates installs that predate this switch.
drop index if exists idx_messages_embedding;

-- Speeds up the backfill's "rows still missing a vector" scan.
create index if not exists idx_messages_embedding_pending
  on messages (created_at)
  where embedding is null;

-- Top-K message snippets by cosine similarity (cross-thread). Only real
-- conversation turns (user/assistant) are searchable; system/tool rows and
-- unembedded rows are excluded. The caller filters by threshold + excludes the
-- current thread.
create or replace function match_messages(
  query_embedding vector(768),
  match_count int default 8
)
returns table (
  id uuid,
  thread_id uuid,
  role text,
  content text,
  created_at timestamptz,
  similarity float
)
language sql stable
as $$
  select m.id, m.thread_id, m.role, m.content, m.created_at,
         1 - (m.embedding <=> query_embedding) as similarity
  from messages m
  where m.embedding is not null
    and m.role in ('user', 'assistant')
  order by m.embedding <=> query_embedding
  limit match_count;
$$;

