-- ============================================================
-- notes.sql
-- ============================================================
-- Spectre notes + todos store.
-- Run once in Supabase SQL Editor. Safe to rerun.
--
-- Two kinds in the same table:
--   kind='note' → free-form thought/idea the user dictated. Optional `pinned`.
--   kind='todo' → structured task. Optional `deadline`, `priority`,
--                 `done` checkbox.
--
-- Distinct from `memory` which holds long-term facts about the user /
-- projects. Spectre saves notes via note.add / todo.add and retrieves
-- with note.list / note.search.

create table if not exists notes (
  id                uuid primary key default gen_random_uuid(),
  kind              text not null default 'note' check (kind in ('note', 'todo')),
  content           text not null,
  pinned            boolean not null default false,
  -- todo-specific (null for kind='note')
  deadline          timestamptz,
  priority          text check (priority in ('low', 'medium', 'high', 'urgent')),
  done              boolean not null default false,
  done_at           timestamptz,
  -- provenance
  source_msg_id     uuid references messages(id) on delete set null,
  source_thread_id  uuid references threads(id) on delete set null,
  created_at        timestamptz not null default now(),
  updated_at        timestamptz not null default now()
);

create index if not exists notes_kind_idx on notes (kind);
create index if not exists notes_created_at_idx on notes (created_at desc);
create index if not exists notes_pinned_idx on notes (pinned) where pinned = true;
create index if not exists notes_todo_open_idx on notes (deadline asc nulls last) where kind = 'todo' and done = false;

-- Service role full access; anon none (notes are personal).
alter table notes enable row level security;

drop policy if exists "service role full access" on notes;
DROP POLICY IF EXISTS "service role full access" ON notes;
CREATE POLICY "service role full access" ON notes
  using (auth.role() = 'service_role')
  with check (auth.role() = 'service_role');

-- ============================================================
-- pdf_library.sql
-- ============================================================
-- ============================================================
-- PDF LIBRARY — documents + RAG chunks + reading-session threads
-- ============================================================
-- Idempotent migration. Run via Supabase SQL editor (or psql).
-- Adds:
--   * pdf_documents — uploaded PDF metadata + intake status
--   * pdf_chunks    — page-aware text chunks with pgvector embeddings
--   * threads.metadata column — used to mark a thread as a "reading
--                               session" so /api/threads/[id]/messages
--                               can scope RAG retrieval to its pdf_ids
--   * match_pdf_chunks RPC for top-k cosine retrieval
-- ============================================================

CREATE TABLE IF NOT EXISTS pdf_documents (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  filename      TEXT NOT NULL,
  title         TEXT,
  summary       TEXT,
  category      TEXT,
  tags          TEXT[] DEFAULT '{}',
  status        TEXT NOT NULL DEFAULT 'pending'
                CHECK (status IN ('pending','processing','ready','failed')),
  file_path     TEXT NOT NULL,
  file_size     BIGINT,
  page_count    INTEGER,
  error         TEXT,
  uploaded_at   TIMESTAMPTZ DEFAULT NOW(),
  processed_at  TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_pdf_documents_status   ON pdf_documents(status);
CREATE INDEX IF NOT EXISTS idx_pdf_documents_uploaded ON pdf_documents(uploaded_at DESC);

CREATE TABLE IF NOT EXISTS pdf_chunks (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  doc_id        UUID NOT NULL REFERENCES pdf_documents(id) ON DELETE CASCADE,
  chunk_index   INTEGER NOT NULL,
  page_start    INTEGER NOT NULL,
  page_end      INTEGER NOT NULL,
  text          TEXT NOT NULL,
  token_count   INTEGER,
  embedding     vector(768),
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_pdf_chunks_doc       ON pdf_chunks(doc_id);
-- NOTE: no ivfflat/approximate vector index on purpose. match_pdf_chunks ALWAYS
-- filters `WHERE doc_id = ANY(doc_ids)` (a reading session = a handful of PDFs),
-- so the planner filters on idx_pdf_chunks_doc first and does an EXACT cosine
-- sort over that small subset — sub-ms and always correct. An ivfflat index here
-- is actively harmful: a single-probe scan lands in a list that may hold none of
-- the attached docs' chunks, returning 0 hits so RAG silently never fires (the
-- same pgvector small-table/post-filter trap that bit generated_media).

-- threads.metadata: marks a thread as kind='pdf-session' and stores
-- the open-set of pdf_ids it's bound to. Used by the chat route to
-- scope RAG retrieval. Defaults to '{}' so existing threads keep
-- working unchanged.
ALTER TABLE threads ADD COLUMN IF NOT EXISTS metadata JSONB DEFAULT '{}'::jsonb;
CREATE INDEX IF NOT EXISTS idx_threads_metadata_kind ON threads ((metadata->>'kind'));

-- Top-k retrieval scoped to the open-set of PDFs.
CREATE OR REPLACE FUNCTION match_pdf_chunks(
  query_embedding vector(768),
  doc_ids UUID[],
  match_count INT
) RETURNS TABLE (
  id UUID,
  doc_id UUID,
  page_start INT,
  page_end INT,
  text TEXT,
  similarity FLOAT
) LANGUAGE sql STABLE AS $$
  SELECT
    id,
    doc_id,
    page_start,
    page_end,
    text,
    1 - (embedding <=> query_embedding) AS similarity
  FROM pdf_chunks
  WHERE doc_id = ANY(doc_ids) AND embedding IS NOT NULL
  ORDER BY embedding <=> query_embedding
  LIMIT match_count;
$$;

-- ============================================================
-- generated-media.sql
-- ============================================================
-- Generated media library: screenshots (+ other generated images) with metadata
-- and an embedding, so (a) the agent can RESURFACE past media by description and
-- (b) the UI (Memory tab / Library) can browse it. The image bytes live on the
-- /generated rail (files); this table is the index + recall layer.

create table if not exists generated_media (
  id          uuid primary key default gen_random_uuid(),
  name        text not null unique,                 -- /generated/<name> filename
  url         text not null,                        -- /generated/<name>
  kind        text not null default 'screenshot',   -- screenshot | image
  caption     text,                                 -- human/agent description (embedded)
  thread_id   uuid references threads(id) on delete set null,
  embedding   vector(768),                          -- nomic-embed-text (EMBED_DIM)
  created_at  timestamptz not null default now()
);

create index if not exists idx_generated_media_created on generated_media (created_at desc);
-- NOTE: deliberately NO ivfflat/approximate index. A media library is small
-- (hundreds–thousands of rows), where an exact KNN sort is sub-millisecond AND
-- always correct. ivfflat with a fixed `lists` count silently drops recall on
-- small tables (a single-probe query lands in an empty list -> 0 rows), which is
-- exactly wrong for "resurface this image". match_generated_media does an exact
-- `order by embedding <=> query` instead.

-- Top-K cosine recall over captions (rows without an embedding are skipped).
create or replace function match_generated_media(
  query_embedding vector(768),
  match_count int default 12
)
returns table (
  id uuid,
  name text,
  url text,
  kind text,
  caption text,
  created_at timestamptz,
  similarity float
)
language sql stable
as $$
  select g.id, g.name, g.url, g.kind, g.caption, g.created_at,
         1 - (g.embedding <=> query_embedding) as similarity
  from generated_media g
  where g.embedding is not null
  order by g.embedding <=> query_embedding
  limit match_count;
$$;

