  scopes        text,                         -- granted scopes, space-separated
  created_at    timestamptz not null default now(),
  updated_at    timestamptz not null default now(),
  unique (provider, account_email)           -- re-connecting an account updates it
);

create index if not exists connected_accounts_provider_idx
  on connected_accounts (provider);

-- Service role has full access; anon/authenticated have none (tokens are internal).
alter table connected_accounts enable row level security;

DROP POLICY IF EXISTS "service role full access" ON connected_accounts;
CREATE POLICY "service role full access" ON connected_accounts
  using (auth.role() = 'service_role')
  with check (auth.role() = 'service_role');

-- ============================================================
-- scheduled_jobs.sql
-- ============================================================
-- Spectre durable scheduler.
-- Run once in Supabase SQL Editor. Safe to rerun.

create table if not exists scheduled_jobs (
  id                uuid primary key default gen_random_uuid(),
  name              text not null,
  description       text,
  enabled           boolean not null default true,
  schedule_type     text not null check (schedule_type in ('once', 'interval', 'daily')),
  interval_seconds  integer,
  run_at            timestamptz,
  time_of_day       text,
  timezone          text not null default 'UTC',
  target_type       text not null check (target_type in ('chat', 'workshop', 'notify')),
  prompt            text not null,
  model_hint        text,
  thread_id         uuid references threads(id) on delete set null,
  status            text not null default 'idle' check (status in ('idle', 'running', 'failed', 'paused')),
  last_run_at       timestamptz,
  next_run_at       timestamptz,
  last_error        text,
  locked_at         timestamptz,
  locked_by         text,
  created_at        timestamptz not null default now(),
  updated_at        timestamptz not null default now()
);

create table if not exists scheduled_job_runs (
  id            uuid primary key default gen_random_uuid(),
  job_id        uuid not null references scheduled_jobs(id) on delete cascade,
  status        text not null default 'running' check (status in ('running', 'completed', 'failed', 'cancelled')),
  started_at    timestamptz not null default now(),
  completed_at  timestamptz,
  output        text,
  error         text,
  thread_id     uuid references threads(id) on delete set null,
  metadata      jsonb not null default '{}'
);

create index if not exists idx_scheduled_jobs_due
  on scheduled_jobs(enabled, next_run_at)
  where enabled = true;

create index if not exists idx_scheduled_job_runs_job
  on scheduled_job_runs(job_id, started_at desc);

create or replace function touch_scheduled_jobs_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

drop trigger if exists scheduled_jobs_updated_at on scheduled_jobs;
DROP TRIGGER IF EXISTS scheduled_jobs_updated_at ON scheduled_jobs;
CREATE TRIGGER scheduled_jobs_updated_at
  before update on scheduled_jobs
  for each row
  execute function touch_scheduled_jobs_updated_at();

-- ============================================================
-- scheduled_jobs_routines.sql
-- ============================================================
-- Tempus "Routines" — adds push-on-done to the durable scheduler.
-- Run once in Supabase SQL Editor. Safe to rerun.
--
-- When a `chat` job with notify_on_done = true finishes successfully, the
-- scheduler worker fires a push notification deep-linking to the thread that
-- holds the produced report. See worker/scheduler.mjs.

alter table scheduled_jobs
  add column if not exists notify_on_done boolean not null default false;

-- Per-routine persistent state list, carried across one-shot runs. The
-- scheduler injects list_items into the run prompt and parses a trailing
-- ```routine-ops``` block from the output to add/remove items. list_kind is a
-- free label (blacklist | whitelist | notes | reminders | todos | ...) that
-- only changes the wording of the injected instructions. See
-- worker/routine-list.mjs.
alter table scheduled_jobs
  add column if not exists list_kind text,
  add column if not exists list_items jsonb not null default '[]';

-- ============================================================
-- skillopt.sql
-- ============================================================
-- SkillOpt — the optimization-round LEDGER (Step 4).
-- Run once in Supabase SQL Editor. Safe to rerun (idempotent).
--
-- One row per offline optimization ROUND for a skill: the train score, the
-- validation-gate decision (incumbent vs candidate val scores + delta), whether
-- the candidate was ACCEPTED, how many edits were applied, the held-out test
-- score of the champion, and a metadata blob carrying the proposed edits + a
-- line diff so a round can be eyeballed after the fact.
--
-- This is a DRY-RUN ledger: accepting a candidate writes skill_vN.md +
-- best_skill.md on disk (both gitignored) — it NEVER touches the live
-- skills/<skill>/SKILL.md. That deploy is Step 6, behind the workshop gate, and
-- is what `workshop_task_id` will eventually link to.
--
-- RLS idiom mirrors supabase/notes.sql exactly: service role full access, anon
-- none (this is personal optimization history).

create table if not exists skillopt_runs (
  id                    uuid primary key default gen_random_uuid(),
  skill_name            text not null,
  parent_version        text,
  new_version           text,
  train_score           float,
  incumbent_val_score   float,
  candidate_val_score   float,
  val_delta             float,
  accepted              boolean not null default false,
  edit_count            int,
  test_score            float,
  workshop_task_id      uuid,
  metadata              jsonb,
  created_at            timestamptz not null default now()
);

create index if not exists idx_skillopt_runs_skill_created
  on skillopt_runs (skill_name, created_at desc);

-- Service role full access; anon none (optimization history is personal).
alter table skillopt_runs enable row level security;

drop policy if exists "service role full access" on skillopt_runs;
DROP POLICY IF EXISTS "service role full access" ON skillopt_runs;
CREATE POLICY "service role full access" ON skillopt_runs
  using (auth.role() = 'service_role')
  with check (auth.role() = 'service_role');

-- ============================================================
-- skillopt-deploy.sql
-- ============================================================
-- SkillOpt — Step 6: the APPROVAL-GATED DEPLOY column.
-- Run once in Supabase SQL Editor. Safe to rerun (idempotent).
--
-- Adds `deploy_status` to the skillopt_runs ledger (supabase/skillopt.sql).
--
-- The whole point of Step 6: an ACCEPTED candidate (val-gate passed) becomes a
-- PENDING deploy — it does NOT auto-promote to the live skills/<skill>/SKILL.md.
-- Only an EXPLICIT human approve action copies the gitignored candidate
-- (skillopt/envs/<skill>/skill_v<N>.md) onto the live doc.
--
--   deploy_status NULL        → not a deploy candidate (a rejected round)
--   deploy_status 'pending'   → accepted, awaiting human approval (no live write)
--   deploy_status 'approved'  → human approved; the live SKILL.md WAS written
--   deploy_status 'discarded' → human discarded; the live SKILL.md untouched
--
-- `deployed_at` is stamped when (and only when) a deploy is approved.
--
-- RLS stays exactly as skillopt.sql left it (service role full access, anon
-- none) — adding a column does not change the policy, so nothing to redo here.

alter table skillopt_runs
  add column if not exists deploy_status text;

alter table skillopt_runs
  add column if not exists deployed_at timestamptz;

-- Constrain the allowed values (NULL allowed = not a deploy candidate).
-- drop-then-add so a rerun re-applies the latest definition cleanly.
alter table skillopt_runs
  drop constraint if exists skillopt_runs_deploy_status_check;
alter table skillopt_runs
  add constraint skillopt_runs_deploy_status_check
  check (deploy_status is null or deploy_status in ('pending', 'approved', 'discarded'));

-- Pending deploys are read on every approval-gate poll (listPendingDeploys()).
create index if not exists idx_skillopt_runs_deploy_pending
  on skillopt_runs (created_at desc)
  where deploy_status = 'pending';

-- ============================================================
-- tempus-native.sql
-- ============================================================
-- supabase/tempus-native.sql
-- Native Tempus tables in Spectre's Supabase. Prefixed `tempus_` to
-- avoid collision with anything else in the schema. Safe to rerun.

create table if not exists tempus_projects (
  id           text primary key,
  name         text not null,
  color        text not null default '#6366f1',
