create index if not exists tempus_projects_archived_idx on tempus_projects(is_archived) where is_archived = false;

-- ============================================================
-- tool_policies.sql
-- ============================================================
-- Persistent tool-permission policies + a call log (quotas/audit).
-- Today the permission broker is module-level in-memory: a core restart cancels
-- every in-flight approval and `allow_session` doesn't survive. These tables let
-- a decision PERSIST (auto-resolve without re-prompting) and bound autonomous
-- tool use with optional per-tool hourly quotas. Safe to rerun.

create table if not exists tool_policies (
  id          uuid primary key default gen_random_uuid(),
  tool        text not null,                       -- e.g. mcp__spectre__bash
  scope       text not null default 'global'
              check (scope in ('global','thread','module')),
  scope_id    text,                                -- thread_id / module id; null = global
  decision    text not null check (decision in ('always_allow','always_deny')),
  quota_per_hour int,                              -- null = unlimited
  expires_at  timestamptz,                         -- null = no expiry (allow_session sets a TTL)
  created_at  timestamptz not null default now()
);

-- One live policy per (tool, scope, scope_id); a new decision replaces the old.
create unique index if not exists uq_tool_policies_target
  on tool_policies (tool, scope, coalesce(scope_id, ''));
create index if not exists idx_tool_policies_lookup
  on tool_policies (tool, scope, scope_id);

-- Audit + quota source: one row per resolved gated tool call.
create table if not exists tool_calls (
  id          uuid primary key default gen_random_uuid(),
  tool        text not null,
  thread_id   text,
  decision    text not null,                       -- 'allow' | 'deny'
  auto        boolean not null default false,      -- resolved by a policy (no prompt)
  created_at  timestamptz not null default now()
);
create index if not exists idx_tool_calls_tool_time on tool_calls (tool, created_at desc);

-- ============================================================
-- workshop-realtime.sql
-- ============================================================
-- Realtime for the workshop worker: it subscribes to workshop_tasks UPDATEs
-- (status -> pending picks up a task; status -> cancelled kills the run).
-- replica identity full so UPDATE payloads carry the row. Safe to rerun.
alter table workshop_tasks replica identity full;

do $$
begin
  if not exists (
    select 1 from pg_publication_tables
    where pubname = 'supabase_realtime' and tablename = 'workshop_tasks'
  ) then
    alter publication supabase_realtime add table workshop_tasks;
  end if;
end $$;

-- ============================================================
-- dream-default-schedule.sql
-- ============================================================
-- Nightly maintenance schedule (the scheduler's 'dream' target).
-- Run once in Supabase SQL Editor. Safe to rerun.
--
-- POST /api/dream/nightly runs memory consolidation (backfill + dedupe/merge +
-- decay) and a system health sweep (providers + storage -> debugging engine).
-- Dispatch is handled by worker/scheduler.mjs when target_type = 'dream'.
-- (Continuous learning happens per-turn via learnFromExchange, so the old
-- batch thread-distill /api/dream/run was removed.)

-- 1. Allow target_type = 'dream' on scheduled_jobs.
alter table scheduled_jobs drop constraint if exists scheduled_jobs_target_type_check;
alter table scheduled_jobs add constraint scheduled_jobs_target_type_check
  check (target_type in ('chat', 'workshop', 'notify', 'dream', 'proactive', 'skillopt', 'skill_curation'));

-- 2. Insert the daily 03:30 dream schedule if no row exists yet.
insert into scheduled_jobs (
  name,
  description,
  enabled,
  schedule_type,
  time_of_day,
  timezone,
  target_type,
  prompt,
  next_run_at
)
select
  'dream-mode',
  'Nightly maintenance — memory consolidation (dedupe/decay) + system health sweep.',
  true,
  'daily',
  '03:30',
  'UTC',
  'dream',
  'POST /api/dream/nightly',
  case
    when now() < date_trunc('day', now()) + interval '3 hours 30 minutes'
      then date_trunc('day', now()) + interval '3 hours 30 minutes'
    else date_trunc('day', now()) + interval '1 day 3 hours 30 minutes'
  end
where not exists (
  select 1 from scheduled_jobs
  where name = 'dream-mode' and target_type = 'dream'
);

-- ============================================================
-- proactive-default-schedule.sql
-- ============================================================
-- Bounded proactive run (the scheduler's 'proactive' target) — P1.1.
-- Run once in Supabase SQL Editor. Safe to rerun.
--
-- POST /api/proactive/bounded-run spawns Spectre's proactive brain with a SAFE,
-- read-mostly MCP tool whitelist (memory read/write, push notify, schedule /
-- calendar / analytics READ) under a wall-clock + per-tool hourly quota budget.
-- It pre-seeds short-TTL always_allow tool_policies so whitelisted calls
-- auto-resolve, captures the run to monitor_events, and degrades to the
-- proposal-only heartbeat if the tool_policies table isn't applied yet.
-- Dispatch is handled by worker/scheduler.mjs when target_type = 'proactive'.
--
-- Depends on supabase/tool_policies.sql (P1.2) for full tool-using behaviour;
-- without it the run still works but degrades to proposal-only.

-- 1. Allow target_type = 'proactive' on scheduled_jobs (keep prior targets).
alter table scheduled_jobs drop constraint if exists scheduled_jobs_target_type_check;
alter table scheduled_jobs add constraint scheduled_jobs_target_type_check
  check (target_type in ('chat', 'workshop', 'notify', 'dream', 'proactive', 'skillopt', 'skill_curation'));

-- 2. Insert a 4-hourly proactive schedule if no row exists yet (matches the
--    legacy heartbeat cadence). Disabled by default — flip enabled=true once
--    tool_policies.sql is applied and you want the brain acting on its own.
insert into scheduled_jobs (
  name,
  description,
  enabled,
  schedule_type,
  interval_seconds,
  timezone,
  target_type,
  prompt,
  next_run_at
)
select
  'proactive-run',
  'Bounded proactive turn — Spectre acts on its own with a safe tool whitelist (memory/notify/read-only) under a wall-clock + quota budget.',
  false,
  'interval',
  14400,
  'UTC',
  'proactive',
  'POST /api/proactive/bounded-run',
  now() + interval '4 hours'
where not exists (
  select 1 from scheduled_jobs
  where name = 'proactive-run' and target_type = 'proactive'
);

-- ============================================================
-- skillopt-schedule.sql
-- ============================================================
-- SkillOpt run schedule (the scheduler's 'skillopt' target) — Step 5.
-- Run once in Supabase SQL Editor. Safe to rerun (idempotent).
--
-- POST /api/skillopt/run drives ONE bounded offline optimization round for the
-- configured skill (rollout incumbent on train -> score -> OPUS proposes edits ->
-- budget -> apply -> VALIDATION GATE on val -> evaluate champion on test) and
-- ledgers the result to skillopt_runs. It is a DRY-RUN: accepting a candidate
-- writes skill_vN.md + best_skill.md on disk (both gitignored) — it NEVER touches
-- the live skills/<skill>/SKILL.md. That workshop-gated deploy is Step 6.
-- Dispatch is handled by worker/scheduler.mjs when target_type = 'skillopt'.
--
-- Depends on supabase/skillopt.sql (the skillopt_runs ledger, Step 4).

-- 1. Allow target_type = 'skillopt' on scheduled_jobs (keep prior targets).
alter table scheduled_jobs drop constraint if exists scheduled_jobs_target_type_check;
alter table scheduled_jobs add constraint scheduled_jobs_target_type_check
  check (target_type in ('chat', 'workshop', 'notify', 'dream', 'proactive', 'skillopt', 'skill_curation'));

-- 2. Insert a weekly off-hours SkillOpt schedule if no row exists yet.
--    DISABLED by default — flip enabled=true once you want the optimizer to run
--    offline rounds on its own. The cadence (~weekly, 604800s) runs well after
--    the nightly dream pass so the two never contend for the model. The skill to
--    optimize is carried in the prompt field (default 'memory'); the run endpoint
--    parses it from there. interval_seconds is used because the schema's
--    schedule_type CHECK is ('once','interval','daily') — there is no 'weekly',
--    so a 7-day interval is the schema-compatible way to express ~weekly.
insert into scheduled_jobs (
  name,
  description,
  enabled,
  schedule_type,
  interval_seconds,
  timezone,
  target_type,
  prompt,
  next_run_at
)
select
  'skillopt-run',
  'Weekly bounded SkillOpt optimization round for the configured skill (rollout -> reflect -> val-gate -> test). DRY-RUN: ledgers to skillopt_runs, never writes the live SKILL.md. Disabled by default.',
  false,
  'interval',
  604800,
  'UTC',
  'skillopt',
  'memory',
  now() + interval '7 days'
where not exists (
  select 1 from scheduled_jobs
  where name = 'skillopt-run' and target_type = 'skillopt'
);

-- ============================================================
-- skill-usage.sql
-- ============================================================
-- Skill-usage telemetry + the weekly curation proposal schedule.
